// src/lib/mcp/tools/list-stories.ts
var list_stories_default = defineTool2({
  name: "list_stories",
  title: "List Kwendi stories",
  description: "List Angolan cultural stories available in Kwendi with their region, era, level, and duration. Optionally filter by level.",
  inputSchema: {
    nivel: z2.enum(["Iniciante", "Interm\xE9dio", "Avan\xE7ado"]).optional()
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ nivel }) => {
    const items = HISTORIAS.filter((h) => !nivel || h.nivel === nivel).map((h) => ({
      id: h.id,
      titulo: h.titulo,
      subtitulo: h.subtitulo,
      regiao: h.regiao,
      epoca: h.epoca,
      nivel: h.nivel,
      duracaoMin: h.duracaoMin
    }));
    return {
      content: [{ type: "text", text: JSON.stringify(items, null, 2) }],
      structuredContent: { items, count: items.length }
    };
  }
});

