// src/lib/mcp/tools/list-curiosities.ts
var list_curiosities_default = defineTool3({
  name: "list_curiosities",
  title: "List Angolan culture curiosities",
  description: "List cultural curiosities from Kwendi (nature, history, culture, gastronomy, languages, monuments of Angola). Optionally filter by category.",
  inputSchema: {
    categoria: z3.enum(["natureza", "historia", "cultura", "gastronomia", "linguas", "monumentos"]).optional()
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ categoria }) => {
    const items = curiosidades.filter((c) => !categoria || c.categoria === categoria).map((c) => ({
      categoria: c.categoria,
      titulo: c.titulo,
      subtitulo: c.subtitulo,
      resumo: c.resumo
    }));
    return {
      content: [{ type: "text", text: JSON.stringify(items, null, 2) }],
      structuredContent: { items, count: items.length }
    };
  }
});

// src/lib/mcp/index.ts
var mcp_default = defineMcp({
  name: "kwendi-mcp",
  title: "Kwendi MCP",
  version: "0.1.0",
  instructions: "Tools for Kwendi, an app to learn the Umbundu language and Angolan culture. Use `search_dictionary` for PT \u21C4 Umbundu lookups, `list_stories` for Angolan tales, and `list_curiosities` for cultural facts about Angola.",
  tools: [search_dictionary_default, list_stories_default, list_curiosities_default]
});

// lovable-mcp-supabase-entry.ts
import { createSupabaseHandler } from "npm:@lovable.dev/mcp-js@0.20.0/stacks/supabase";
Deno.serve(createSupabaseHandler(mcp_default, { functionName: "mcp" }));
